private boolean isEmptyObject(JsonParser p) throws IOException {
    JsonToken t = p.nextToken();
    if (t == JsonToken.END_OBJECT) {
        return true;
    }
    return false;
}

private boolean isEmptyArray(JsonParser p) throws IOException {
    JsonToken t = p.nextToken();
    if (t == JsonToken.END_ARRAY) {
        return true;
    }
    return false;
}

